UPDATE reservation SET status=#{status},
cancelled_at = CASE WHEN #{status}='CANCELLED' THEN NOW() ELSE cancelled_at END
WHERE reservation_id=#{reservationId}

mapper.select:
SELECT COUNT(*)
FROM reservation
WHERE status = #{status}

SELECT r.*, p.title AS performance_title, p.venue_name AS venue, m.name AS member_name, m.email AS member_email, m.phone AS member_phone, sc.show_date, sc.show_time, pay.status AS payment_status, pay.method AS payment_method, el.checked_in_at FROM reservation r JOIN member m ON r.member_id = m.member_id JOIN schedule sc ON r.schedule_id = sc.schedule_id JOIN performance p ON sc.performance_id = p.performance_id LEFT JOIN payment pay ON pay.reservation_id = r.reservation_id LEFT JOIN entrance_log el ON el.reservation_id = r.reservation_id
AND r.status = #{status}
AND ( r.reservation_no LIKE CONCAT('%', #{keyword}, '%') OR m.name LIKE CONCAT('%', #{keyword}, '%') OR m.email LIKE CONCAT('%', #{keyword}, '%') OR p.title LIKE CONCAT('%', #{keyword}, '%') )
ORDER BY r.created_at DESC LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*) FROM reservation r JOIN member m ON r.member_id = m.member_id JOIN schedule sc ON r.schedule_id = sc.schedule_id JOIN performance p ON sc.performance_id = p.performance_id
AND r.status = #{status}
AND ( r.reservation_no LIKE CONCAT('%', #{keyword}, '%') OR m.name LIKE CONCAT('%', #{keyword}, '%') OR m.email LIKE CONCAT('%', #{keyword}, '%') OR p.title LIKE CONCAT('%', #{keyword}, '%') )

SELECT r.*, p.title AS performance_title, p.venue_name AS venue,
       sc.show_date, sc.show_time, pay.method AS payment_method
FROM reservation r
JOIN schedule sc ON r.schedule_id = sc.schedule_id
JOIN performance p ON sc.performance_id = p.performance_id
LEFT JOIN payment pay ON pay.reservation_id = r.reservation_id
WHERE r.member_id = #{memberId}
AND r.status = #{status}
ORDER BY r.created_at DESC
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*)
FROM reservation r
WHERE r.member_id = #{memberId}
AND r.status = #{status}
